import{_ as o,o as r,c as t,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"22. Hours Of Work","description":"","frontmatter":{"title":"22. Hours Of Work","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","hours","shift-work","employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/22-hours-of-work.md","filePath":"ebas/has-managers-admin/health-allied-services/hours-of-work/22-hours-of-work.md"}'),s={name:"ebas/has-managers-admin/health-allied-services/hours-of-work/22-hours-of-work.md"};function n(i,e,h,u,l,p){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="_22-hours-of-work" tabindex="-1">22. Hours Of Work <a class="header-anchor" href="#_22-hours-of-work" aria-label="Permalink to &quot;22. Hours Of Work&quot;">​</a></h1><p><strong>22.1</strong> The ordinary hours of work for a full-time Employee will be 38 hours, or an average of 38 hours, per week in a fortnight or 4-week period.</p><p><strong>22.2</strong> For the purposes of subclause 22.1, the ordinary hours an Employee works in a week are taken to include any hours of authorised leave, or absence, whether paid or unpaid, that the Employee takes in a week.</p><p><strong>22.3</strong> The working week will commence at midnight on a Sunday.</p><p><strong>22.4</strong> Notwithstanding any authorised meal breaks or rest breaks, the work of each day/shift will be continuous.</p><p><strong>22.5</strong> Any Employee required to work more than six consecutive periods of duty without 24 hours off duty will be paid for the seventh and any further consecutive period of ordinary duty worked at the rate of triple time until they have been given 24 hours off duty.</p><p><strong>22.6</strong> 12-hour shifts</p><p><strong>(a)</strong> 12-hour shifts may be performed by mutual agreement between each Employee and Employer provided that:</p><p><strong>(i)</strong> The Employer must notify the HWU of any requests to engage an Employee on 12-hour shift arrangements and consult where requested;</p><p><strong>(ii)</strong> The Employer must monitor each Employee in accordance with the Work-Related Fatigue clause at Section 1, clause 78.2;</p><p><strong>(iii)</strong> The Employer must ensure that any Employee working 12-hour shifts will not be paid any less than the relevant Modern Award entitlement; and</p><p><strong>(iv)</strong> The Employee must be provided 10 consecutive hours off duty after each 12-hour shift, otherwise Overtime rates apply for each hour worked until the 10 consecutive hours off duty is provided.</p><p>Plain language terms: ordinary hours, weekly hours.</p>',13)])])}const m=o(s,[["render",n]]);export{f as __pageData,m as default};
